import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  describe("empty and trivial inputs", () => {
    // Bug: special-casing [] wrong, or returning input array instead of new one.
    it("returns [] for empty input", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    // Bug: dropping or duplicating a lone interval.
    it("returns a single interval unchanged", () => {
      expect(mergeIntervals([[3, 7]])).toEqual([[3, 7]]);
    });
  });

  describe("overlap / touch / disjoint (the three core rules)", () => {
    // Bug: failing to merge overlapping intervals. [1,4] and [3,6] overlap at 3..4.
    it("merges overlapping intervals into one", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    // Bug: using `<` instead of `<=` at the touching boundary would leave
    // [1,2] and [2,3] separate. This is the exact end==start boundary.
    it("merges touching intervals that share an endpoint", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    // Bug: over-eager merge. A gap of 1 (end=2, next start=3) must NOT merge.
    it("keeps disjoint intervals separate (gap just above the boundary)", () => {
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });
  });

  describe("boundary sweep around the touch point", () => {
    // Just below: next.start = last.end - 1  -> overlap -> merge.
    it("merges when next starts one before the previous end", () => {
      expect(mergeIntervals([[1, 5], [4, 8]])).toEqual([[1, 8]]);
    });

    // At the boundary: next.start = last.end -> touch -> merge.
    it("merges when next starts exactly at the previous end", () => {
      expect(mergeIntervals([[1, 5], [5, 8]])).toEqual([[1, 8]]);
    });

    // Just above: next.start = last.end + 1 -> disjoint -> stay separate.
    it("does not merge when next starts one after the previous end", () => {
      expect(mergeIntervals([[1, 5], [6, 8]])).toEqual([[1, 5], [6, 8]]);
    });
  });

  describe("containment and equality", () => {
    // Bug: setting end = next.end instead of max(...) would shrink [1,10] to
    // [1,3] when a fully-contained interval follows.
    it("keeps the outer bound when an interval is fully contained", () => {
      expect(mergeIntervals([[1, 10], [2, 3]])).toEqual([[1, 10]]);
    });

    // Bug: duplicate handling that emits two copies or drops both.
    it("collapses identical duplicate intervals into one", () => {
      expect(mergeIntervals([[2, 5], [2, 5]])).toEqual([[2, 5]]);
    });
  });

  describe("ordering", () => {
    // Bug: not sorting by start; naive left-to-right merge would leave
    // [5,6] and [1,3] unmerged / out of order.
    it("sorts the output by start ascending regardless of input order", () => {
      expect(mergeIntervals([[5, 6], [1, 3], [2, 4]])).toEqual([[1, 4], [5, 6]]);
    });

    // Bug: cascading merge where a later interval extends the running end.
    // [1,3] merges [2,5]; the combined [1,5] then reaches [5,7].
    it("chains merges as the running end extends", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [5, 7]])).toEqual([[1, 7]]);
    });

    // Bug: an unsorted interval whose end is smaller must not overwrite the
    // running max. After sort: [1,9],[2,4] -> [1,9], then [10,11] disjoint.
    it("preserves the max end across an out-of-order shorter interval", () => {
      expect(mergeIntervals([[2, 4], [10, 11], [1, 9]])).toEqual([
        [1, 9],
        [10, 11],
      ]);
    });
  });

  describe("degenerate and negative values", () => {
    // Bug: assuming positive coords or mishandling zero-width intervals.
    // [0,0] touches [0,5]; [-3,-1] is disjoint and sorts first.
    it("handles zero-width and negative intervals", () => {
      expect(mergeIntervals([[0, 0], [0, 5], [-3, -1]])).toEqual([
        [-3, -1],
        [0, 5],
      ]);
    });
  });

  describe("invalid input", () => {
    // Bug: not validating start <= end. Spec requires a RangeError.
    it("throws RangeError when a pair has start > end", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    // Bug: only checking the first pair, missing an invalid later one.
    it("throws RangeError for an invalid pair anywhere in the list", () => {
      expect(() => mergeIntervals([[1, 2], [9, 3]])).toThrow(RangeError);
    });

    // Bug: rejecting the valid degenerate case start == end.
    it("accepts start == end (does not throw)", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });
  });

  describe("no mutation of input", () => {
    // Bug: sorting/merging in place would reorder the caller's array or
    // rewrite a pair's end. Spec: input array and its pairs are never mutated.
    it("does not mutate the input array or its pairs", () => {
      const input = [[3, 6], [1, 4]];
      const inner = input[0];
      mergeIntervals(input);
      expect(input).toEqual([[3, 6], [1, 4]]);
      expect(inner).toEqual([3, 6]);
    });

    // Bug: returning a pair object aliased to an input pair. Mutating the
    // result must not reach back into the caller's data.
    it("returns intervals that do not alias the input pairs", () => {
      const input = [[1, 4], [3, 6]];
      const result = mergeIntervals(input);
      result[0][1] = 999;
      expect(input).toEqual([[1, 4], [3, 6]]);
    });
  });
});

